-- =============================================
-- 치과 용어 백과사전 (Dental Dictionary)
-- 200+ 용어, 카테고리별 분류, 진료 연동
-- =============================================

CREATE TABLE IF NOT EXISTS dict_categories (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  icon TEXT DEFAULT '',
  sort_order INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS dict_terms (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  category_id INTEGER NOT NULL,
  term TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  pronunciation TEXT DEFAULT '',
  english TEXT DEFAULT '',
  short_desc TEXT NOT NULL,
  full_desc TEXT NOT NULL,
  related_service TEXT DEFAULT '',
  chosung TEXT DEFAULT '',
  views INTEGER DEFAULT 0,
  is_published INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (category_id) REFERENCES dict_categories(id)
);

CREATE INDEX idx_dict_terms_category ON dict_terms(category_id, term);
CREATE INDEX idx_dict_terms_slug ON dict_terms(slug);
CREATE INDEX idx_dict_terms_chosung ON dict_terms(chosung);
CREATE INDEX idx_dict_terms_published ON dict_terms(is_published, category_id);
CREATE INDEX idx_dict_terms_service ON dict_terms(related_service);

