-- ─── 1. 임플란트 (25개) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(1, '임플란트', 'implant', 'Dental Implant', '임플란트', '인공 치아 뿌리를 심어 자연치아처럼 기능하게 하는 시술', '임플란트는 상실된 치아를 대체하기 위해 턱뼈에 티타늄 인공 치근을 심고 그 위에 인공 치관을 연결하는 치료법입니다. 자연치아와 거의 동일한 저작력과 심미성을 회복할 수 있으며, 인접 치아를 삭제하지 않아도 됩니다. 이음치과에서는 CBCT와 구강스캐너를 이용한 디지털 가이드 임플란트를 시행합니다.', 'implant', 'ㅇ'),
(1, '픽스처', 'fixture', 'Fixture', '픽스처', '턱뼈에 심는 나사 모양의 인공 치아 뿌리', '픽스처는 임플란트의 핵심 구성 요소로, 티타늄 또는 지르코니아로 만들어진 나사 형태의 인공 치근입니다. 수술을 통해 턱뼈 속에 식립되며, 뼈와 결합(골유착)되어 인공 치아의 단단한 기반이 됩니다. 일반적으로 3~6개월의 치유 기간이 필요합니다.', 'implant', 'ㅍ'),
(1, '어버트먼트', 'abutment', 'Abutment', '어버트먼트', '픽스처와 보철물을 연결하는 중간 연결체', '어버트먼트는 뼈 속에 심어진 픽스처와 그 위에 올라가는 크라운(보철물)을 연결하는 부품입니다. 환자의 잇몸 두께와 보철물 각도에 맞춰 맞춤 제작됩니다.', 'implant', 'ㅇ'),
(1, '골유착', 'osseointegration', 'Osseointegration', '골유착', '임플란트 픽스처가 뼈와 직접 결합되는 과정', '골유착은 티타늄 임플란트 표면에 새로운 뼈세포가 자라나면서 임플란트와 뼈가 단단하게 결합되는 생물학적 과정입니다. 보통 하악 2~3개월, 상악 4~6개월 소요되며, 이 과정이 완료되어야 최종 보철물을 장착할 수 있습니다.', 'implant', 'ㄱ'),
(1, '골이식', 'bone-graft', 'Bone Graft', '골이식', '임플란트 식립을 위해 부족한 뼈를 보충하는 시술', '뼈의 양이나 높이가 부족할 때 자가골, 이종골, 합성골 등을 이식하여 임플란트를 심을 수 있는 뼈 환경을 만드는 시술입니다. 상악동 거상술(사이너스 리프트)도 골이식의 한 종류입니다.', 'implant', 'ㄱ'),
(1, '상악동 거상술', 'sinus-lift', 'Sinus Lift', '상악동 거상술', '위턱 어금니 부위 뼈가 부족할 때 상악동 점막을 올려 뼈를 채우는 수술', '상악동(부비동)의 바닥 점막을 위로 들어올리고 그 공간에 골이식재를 채워 넣어 임플란트를 심을 수 있는 충분한 뼈 높이를 확보하는 수술입니다. 측방접근법과 치조정접근법 두 가지 방법이 있습니다.', 'implant', 'ㅅ'),
(1, '즉시 임플란트', 'immediate-implant', 'Immediate Implant', '즉시 임플란트', '발치 당일 바로 임플란트를 식립하는 시술', '치아를 발치한 직후 같은 자리에 임플란트를 바로 심는 방법입니다. 수술 횟수와 전체 치료 기간을 줄일 수 있으나, 충분한 뼈와 잇몸 조건이 갖춰져야 가능합니다.', 'implant', 'ㅈ'),
(1, '디지털 가이드', 'digital-guide', 'Digital Surgical Guide', '디지털 가이드', 'CT와 스캔 데이터로 제작한 맞춤형 수술 가이드', '환자의 CBCT 영상과 구강스캐너 데이터를 컴퓨터에서 합성하여 최적의 임플란트 위치·각도·깊이를 미리 계획하고, 3D 프린터로 수술 가이드를 제작합니다. 이음치과에서는 원내에서 직접 제작합니다.', 'implant', 'ㄷ'),
(1, '오스템', 'osstem', 'Osstem Implant', '오스템', '국산 대표 임플란트 브랜드', '오스템임플란트는 대한민국 대표 임플란트 기업으로, 세계 시장 점유율 상위권의 글로벌 브랜드입니다. 다양한 임상 데이터와 긴 역사를 바탕으로 안정적인 성능을 보장합니다.', 'implant', 'ㅇ'),
(1, '네비게이션 임플란트', 'navigation-implant', 'Navigation Implant', '네비게이션 임플란트', '실시간 3D 네비게이션으로 위치를 추적하며 심는 임플란트', '수술 중 실시간으로 드릴의 위치를 3D 화면에서 추적하여 계획된 위치에 정확하게 임플란트를 식립하는 첨단 기술입니다.', 'implant', 'ㄴ'),
(1, '전악 임플란트', 'full-arch-implant', 'Full Arch Implant', '전악 임플란트', '한 악궁의 모든 치아를 임플란트로 복원하는 시술', '상악 또는 하악 전체 치아가 없는 경우 4~8개의 임플란트를 심고 그 위에 고정식 보철물을 연결하는 치료법입니다. All-on-4, All-on-6 등의 방식이 있습니다.', 'implant', 'ㅈ'),
(1, '미니 임플란트', 'mini-implant', 'Mini Implant', '미니 임플란트', '직경이 작은 소형 임플란트', '일반 임플란트보다 직경이 작아(2~3mm) 뼈가 좁은 부위에 사용하거나, 틀니 고정용으로 활용됩니다. 교정에서 고정원으로 쓰이기도 합니다.', 'implant', 'ㅁ'),
(1, '임플란트 주위염', 'peri-implantitis', 'Peri-implantitis', '임플란트 주위염', '임플란트 주변 잇몸과 뼈에 발생하는 염증', '임플란트 주위 조직에 세균이 감염되어 잇몸 염증과 골 소실이 진행되는 질환입니다. 자연치의 치주염과 유사하며, 정기적 관리가 중요합니다.', 'implant', 'ㅇ'),
(1, '힐링 어버트먼트', 'healing-abutment', 'Healing Abutment', '힐링 어버트먼트', '임플란트 수술 후 잇몸 모양을 잡아주는 장치', '임플란트 식립 후 잇몸이 보철물 형태에 맞게 치유되도록 유도하는 임시 연결체입니다. 최종 보철 전에 사용합니다.', 'implant', 'ㅎ'),
(1, 'GBR', 'gbr', 'Guided Bone Regeneration', '지비알', '골유도재생술. 뼈가 부족한 부위에 차폐막과 골이식재를 사용해 뼈를 재생하는 술식', 'GBR은 부족한 뼈를 재생시키기 위해 결손부에 골이식재를 넣고 차폐막으로 덮어 연조직 침입을 차단하면서 뼈세포가 자라나도록 유도하는 시술입니다.', 'implant', 'ㅈ'),

-- ─── 2. 보철·심미 (30개) ───
(2, '크라운', 'crown', 'Crown', '크라운', '치아 전체를 씌우는 보철물', '손상이 심한 치아를 보호하고 기능을 회복하기 위해 치아 전체를 덮어 씌우는 보철물입니다. 금, PFM(도재), 지르코니아, 올세라믹 등 다양한 재료로 제작됩니다.', 'aesthetic', 'ㅋ'),
(2, '라미네이트', 'laminate', 'Laminate Veneer', '라미네이트', '치아 앞면에 얇은 세라믹 껍데기를 붙이는 심미 시술', '치아 표면을 0.3~0.5mm 정도 최소 삭제한 후 얇은 세라믹 쉘을 붙여 치아의 색상, 형태, 크기를 개선하는 심미 보철입니다. 변색, 틈새, 미세 파절 등에 효과적입니다.', 'aesthetic', 'ㄹ'),
(2, '올세라믹', 'all-ceramic', 'All-Ceramic', '올세라믹', '금속 없이 세라믹으로만 제작된 보철물', '금속 프레임 없이 세라믹 소재만으로 만든 크라운 또는 브릿지입니다. 자연치아와 가장 유사한 투명도와 색감을 구현할 수 있어 앞니 보철에 많이 사용됩니다.', 'aesthetic', 'ㅇ'),
(2, '지르코니아', 'zirconia', 'Zirconia', '지르코니아', '강도와 심미성을 모두 갖춘 세라믹 보철 재료', '산화지르코늄으로 만든 고강도 세라믹 소재입니다. 금속보다 강하면서도 자연치아 같은 색감을 재현할 수 있어 크라운, 브릿지, 임플란트 상부 보철에 널리 사용됩니다.', 'aesthetic', 'ㅈ'),
(2, '브릿지', 'bridge', 'Bridge', '브릿지', '빠진 치아 양쪽 치아에 걸쳐 연결하는 고정식 보철', '상실된 치아의 양쪽 인접 치아를 깎아 지대치로 만들고, 3개 이상의 연결된 크라운을 제작하여 빈 공간을 메우는 보철입니다.', 'aesthetic', 'ㅂ'),
(2, 'PFM', 'pfm', 'Porcelain Fused to Metal', '피에프엠', '금속 위에 도자기를 올린 보철물', 'PFM(도재 금속 보철)은 금속 코핑 위에 도자기를 소성하여 만든 크라운입니다. 금속의 강도와 도재의 심미성을 결합한 전통적인 보철 방식입니다.', 'aesthetic', 'ㅍ'),
(2, '인레이', 'inlay', 'Inlay', '인레이', '치아 홈 안쪽을 채우는 간접 수복물', '충치를 제거한 후 구강 밖에서 제작한 맞춤형 수복물로 치아 내부를 채우는 보철입니다. 레진, 금, 세라믹 등으로 만듭니다.', 'aesthetic', 'ㅇ'),
(2, '온레이', 'onlay', 'Onlay', '온레이', '치아 교두(뾰족한 부분)까지 덮는 간접 수복물', '인레이보다 넓은 범위를 수복하는 보철물로, 치아의 교두 부분까지 덮어줍니다. 크라운보다 치아 삭제량이 적습니다.', 'aesthetic', 'ㅇ'),
(2, '의치', 'denture', 'Denture', '의치', '빠진 여러 치아를 대체하는 탈착식 보철물', '틀니라고도 불리며, 여러 개 또는 모든 치아를 대체하는 탈착 가능한 보철물입니다. 부분 의치와 총의치로 나뉩니다.', 'aesthetic', 'ㅇ'),
(2, '임시 보철', 'temporary-crown', 'Temporary Crown', '임시 보철', '최종 보철물이 완성될 때까지 사용하는 임시 치아', '크라운이나 브릿지 제작 기간 동안 치아를 보호하고 심미성을 유지하기 위해 장착하는 임시 보철물입니다. 주로 레진으로 제작됩니다.', 'aesthetic', 'ㅇ'),
(2, '치아 미백', 'teeth-whitening', 'Teeth Whitening', '치아 미백', '변색된 치아를 하얗게 만드는 시술', '과산화수소 등의 미백 성분을 이용하여 치아의 색을 밝게 하는 시술입니다. 전문가 미백(오피스 미백)과 자가 미백(홈 미백)이 있습니다.', 'aesthetic', 'ㅊ'),
(2, '치아 성형', 'tooth-contouring', 'Tooth Contouring', '치아 성형', '치아의 형태를 다듬어 심미성을 개선하는 시술', '치아 끝을 다듬거나, 레진·라미네이트 등을 이용하여 치아의 크기, 형태, 배열을 개선하는 종합적인 심미 치료입니다.', 'aesthetic', 'ㅊ'),
(2, '심미 보철', 'cosmetic-prosthetics', 'Cosmetic Prosthetics', '심미 보철', '기능과 아름다움을 동시에 고려한 보철 치료', '단순한 기능 회복을 넘어 자연치아와 조화로운 색상, 형태, 투명도를 구현하는 보철 치료 분야입니다.', 'aesthetic', 'ㅅ'),
(2, '교합', 'occlusion', 'Occlusion', '교합', '위아래 치아가 맞물리는 상태', '상악과 하악의 치아가 서로 맞닿는 관계를 말합니다. 올바른 교합은 저작, 발음, 턱관절 건강에 중요하며, 보철 치료 시 정밀한 교합 조정이 필수입니다.', 'aesthetic', 'ㄱ'),
(2, '색조 매칭', 'shade-matching', 'Shade Matching', '색조 매칭', '보철물 색상을 자연치아에 맞추는 과정', '인접 치아와 동일한 색상을 재현하기 위해 색조 가이드와 디지털 기기를 이용하여 보철물의 색을 정밀하게 결정하는 과정입니다.', 'aesthetic', 'ㅅ'),

-- ─── 3. 보존·근관 (25개) ───
(3, '충치', 'cavity', 'Dental Cavity (Caries)', '충치', '세균에 의해 치아가 손상되는 질환', '구강 내 세균이 음식물의 당분을 분해하면서 산을 만들어 치아의 법랑질과 상아질을 녹이는 질환입니다. 초기에는 통증이 없으나 진행되면 신경까지 침범할 수 있습니다.', 'general', 'ㅊ'),
(3, '레진', 'resin', 'Composite Resin', '레진', '치아색 복합 수지 충전 재료', '치아와 유사한 색상의 복합 수지 재료로, 충치 제거 후 빈 공간을 채우는 데 사용됩니다. 심미적이며 당일 치료가 가능합니다. 이음치과의 심미 레진 치료에 사용됩니다.', 'resin', 'ㄹ'),
(3, '신경치료', 'root-canal', 'Root Canal Treatment', '신경치료', '감염된 치아 내부 신경을 제거하고 밀봉하는 치료', '근관치료라고도 하며, 충치나 외상으로 치아 내부의 치수(신경·혈관)가 감염되었을 때 이를 제거하고 근관을 세척·소독한 후 밀봉하는 치료입니다.', 'general', 'ㅅ'),
(3, '근관', 'root-canal-anatomy', 'Root Canal', '근관', '치아 뿌리 내부의 관 모양 공간', '치아 뿌리 안에 치수(신경, 혈관)가 들어있는 좁은 관 모양의 공간입니다. 근관치료 시 이 공간을 깨끗이 소독하고 충전합니다.', 'general', 'ㄱ'),
(3, '치수', 'dental-pulp', 'Dental Pulp', '치수', '치아 내부의 신경과 혈관 조직', '치아 중심부에 위치한 연조직으로, 신경, 혈관, 결합조직으로 구성됩니다. 치아에 영양을 공급하고 통증을 느끼게 합니다.', 'general', 'ㅊ'),
(3, '법랑질', 'enamel', 'Enamel', '법랑질', '치아의 가장 바깥쪽 단단한 층', '인체에서 가장 단단한 조직으로, 치아 표면을 보호하는 하얀 층입니다. 한 번 손상되면 자연 재생이 불가능합니다.', 'general', 'ㅂ'),
(3, '상아질', 'dentin', 'Dentin', '상아질', '법랑질 아래의 치아 주된 구성 조직', '법랑질 아래에 있는 노란빛의 조직으로, 치아의 대부분을 이루며 미세한 관(상아세관)으로 구성되어 있습니다. 노출 시 시린 증상이 나타납니다.', 'general', 'ㅅ'),
(3, '아말감', 'amalgam', 'Amalgam', '아말감', '은·주석·수은 합금의 전통적 충전 재료', '은, 주석, 구리, 수은 등을 혼합한 전통적 충전 재료입니다. 내구성이 좋지만 심미적이지 않아 현재는 레진이나 세라믹으로 대체되는 추세입니다.', 'general', 'ㅇ'),
(3, 'GIC', 'gic', 'Glass Ionomer Cement', '지아이시', '글래스 아이오노머 시멘트. 불소를 방출하는 충전 재료', '유리 분말과 산성 용액을 혼합한 충전 재료로, 치아에 불소를 방출하여 2차 충치를 예방하는 효과가 있습니다. 주로 유치나 임시 충전에 사용됩니다.', 'general', 'ㅈ'),
(3, '치수 복조술', 'pulp-capping', 'Pulp Capping', '치수 복조술', '노출된 치수를 약제로 덮어 보호하는 치료', '충치 제거 중 치수가 노출되었을 때 치수를 살리기 위해 약제(수산화칼슘, MTA 등)를 덮어 보호하는 보존적 치료법입니다.', 'general', 'ㅊ'),
(3, 'MTA', 'mta', 'Mineral Trioxide Aggregate', '엠티에이', '치수 보호 및 근관 치료에 사용되는 생체 친화성 시멘트', 'MTA는 우수한 밀봉력과 생체 적합성을 가진 치과 재료로, 치수 복조, 근관 충전, 천공 수복 등에 사용됩니다.', 'general', 'ㅇ'),
(3, '거타퍼차', 'gutta-percha', 'Gutta Percha', '거타퍼차', '근관 충전에 사용되는 고무 계열 재료', '신경치료 후 깨끗해진 근관 공간을 밀봉하는 데 사용되는 열가소성 재료입니다. 실러와 함께 사용하여 세균 재감염을 방지합니다.', 'general', 'ㄱ'),
(3, '재근관치료', 'retreatment', 'Root Canal Retreatment', '재근관치료', '이전 신경치료가 실패했을 때 다시 시행하는 치료', '기존 근관치료 후 감염이 재발하거나 증상이 지속될 때, 이전 충전재를 제거하고 다시 세척·소독·충전하는 치료입니다.', 'general', 'ㅈ'),
(3, '치근단 절제술', 'apicoectomy', 'Apicoectomy', '치근단 절제술', '치아 뿌리 끝을 외과적으로 제거하는 수술', '근관치료만으로 해결되지 않는 뿌리 끝 감염을 치료하기 위해 잇몸을 절개하고 뿌리 끝과 감염 조직을 제거하는 수술입니다.', 'general', 'ㅊ'),

-- ─── 4. 치주·잇몸 (20개) ───
(4, '치주질환', 'periodontal-disease', 'Periodontal Disease', '치주질환', '잇몸과 치아를 지지하는 조직에 발생하는 질환', '세균성 플라크에 의해 잇몸(치은), 치주인대, 치조골 등 치아 지지 조직에 염증이 생기는 질환입니다. 치은염과 치주염으로 나뉩니다.', 'general', 'ㅊ'),
(4, '치은염', 'gingivitis', 'Gingivitis', '치은염', '잇몸에만 발생하는 초기 단계의 염증', '치아 주위 잇몸에 발생하는 가역적인 염증입니다. 잇몸이 붉어지고, 붓고, 양치 시 출혈이 나타납니다. 적절한 관리로 완치 가능합니다.', 'general', 'ㅊ'),
(4, '치주염', 'periodontitis', 'Periodontitis', '치주염', '뼈까지 파괴되는 심한 잇몸 질환', '치은염이 진행되어 치조골까지 파괴되는 비가역적 질환입니다. 치아가 흔들리고, 최종적으로 치아 상실로 이어질 수 있습니다.', 'general', 'ㅊ'),
(4, '스케일링', 'scaling', 'Dental Scaling', '스케일링', '치석과 치태를 제거하는 치주 기본 치료', '초음파 스케일러와 수기구를 이용하여 치아 표면에 부착된 치석과 치태를 제거하는 시술입니다. 건강보험 적용으로 연 1회 보험 스케일링이 가능합니다.', 'general', 'ㅅ'),
(4, '치석', 'calculus', 'Dental Calculus', '치석', '치태가 석회화되어 딱딱해진 침착물', '플라크(치태)가 타액의 무기질과 결합하여 단단하게 굳은 것입니다. 칫솔로 제거되지 않으며, 치과에서 스케일링으로 제거해야 합니다.', 'general', 'ㅊ'),
(4, '치태', 'plaque', 'Dental Plaque', '치태', '치아 표면에 형성되는 세균막', '구강 내 세균과 음식물 잔사가 결합하여 치아 표면에 형성되는 끈적한 투명 막입니다. 충치와 잇몸병의 주원인입니다.', 'general', 'ㅊ'),
(4, '치조골', 'alveolar-bone', 'Alveolar Bone', '치조골', '치아를 감싸고 지지하는 턱뼈의 일부', '치아가 심어져 있는 턱뼈 부분으로, 치주인대를 통해 치아와 연결됩니다. 치주염이 진행되면 이 뼈가 녹아 치아가 흔들립니다.', 'general', 'ㅊ'),
(4, '치주낭', 'periodontal-pocket', 'Periodontal Pocket', '치주낭', '잇몸과 치아 사이의 비정상적으로 깊어진 틈', '정상적인 잇몸 고랑(1~3mm)이 치주염으로 인해 4mm 이상 깊어진 상태입니다. 깊은 치주낭 안에서 세균이 번식합니다.', 'general', 'ㅊ'),
(4, '잇몸 이식', 'gum-graft', 'Gum Graft', '잇몸 이식', '부족한 잇몸 조직을 이식하는 수술', '잇몸이 퇴축되어 치아 뿌리가 노출된 경우, 구개 등에서 잇몸 조직을 채취하여 부족한 부위에 이식하는 수술입니다.', 'general', 'ㅇ'),
(4, '치근 활택술', 'root-planing', 'Root Planing', '치근 활택술', '치아 뿌리 표면을 깨끗이 다듬는 시술', '스케일링 후 치아 뿌리 표면에 남은 치석과 변성된 시멘트질을 제거하여 매끈하게 다듬는 시술입니다.', 'general', 'ㅊ'),
(4, '잇몸 절제술', 'gingivectomy', 'Gingivectomy', '잇몸 절제술', '과도하게 자란 잇몸 조직을 제거하는 수술', '비후되거나 과도하게 성장한 잇몸 조직을 절제하여 정상적인 잇몸 형태를 회복하는 수술입니다. 거미 스마일 교정에도 사용됩니다.', 'general', 'ㅇ'),
(4, '플랩 수술', 'flap-surgery', 'Flap Surgery', '플랩 수술', '잇몸을 열어 깊은 치석과 감염 조직을 제거하는 수술', '스케일링만으로 제거하기 어려운 깊은 치주낭의 치석과 병든 조직을 제거하기 위해 잇몸을 절개하여 열고 직접 치료하는 수술입니다.', 'general', 'ㅍ'),

-- ─── 5. 턱관절·교정 (20개) ───
(5, '턱관절 장애', 'tmd', 'Temporomandibular Disorder', '턱관절 장애', '턱관절과 주변 근육의 기능 이상', '턱관절(측두하악관절)과 저작근에 발생하는 통증, 소리, 운동 장애 등을 포함하는 질환군입니다. 스트레스, 이갈이, 외상 등이 원인입니다.', 'tmj', 'ㅌ'),
(5, '이갈이', 'bruxism', 'Bruxism', '이갈이', '수면 중 또는 낮에 무의식적으로 이를 가는 습관', '이를 갈거나 꽉 무는 비기능적 습관으로, 치아 마모, 턱관절 통증, 두통, 치아 파절의 원인이 됩니다. 야간 장치(스플린트)로 관리합니다.', 'tmj', 'ㅇ'),
(5, '스플린트', 'splint', 'Occlusal Splint', '스플린트', '턱관절 치료를 위한 교합 안정 장치', '투명 아크릴 재질로 제작된 맞춤형 장치로, 취침 시 착용하여 이갈이로 인한 치아 마모를 방지하고 턱관절의 부담을 줄여줍니다.', 'tmj', 'ㅅ'),
(5, '개구제한', 'limited-opening', 'Limited Mouth Opening', '개구제한', '입을 정상보다 작게만 벌릴 수 있는 상태', '정상 입 벌림(40mm 이상)보다 적게 벌어지는 상태로, 턱관절 장애의 주요 증상 중 하나입니다.', 'tmj', 'ㄱ'),
(5, '관절원판', 'articular-disc', 'Articular Disc', '관절원판', '턱관절 안의 쿠션 역할을 하는 연골 조직', '턱관절 사이에 위치한 섬유연골 디스크로, 입을 벌리고 닫을 때 관절 움직임을 부드럽게 하고 충격을 흡수합니다.', 'tmj', 'ㄱ'),
(5, '교정', 'orthodontics', 'Orthodontics', '교정', '치아 배열과 교합을 바르게 하는 치료', '부정교합이나 치아 배열 이상을 브래킷, 와이어, 투명 교정장치 등을 이용하여 바르게 잡아주는 치과 치료 분야입니다.', 'tmj-ortho', 'ㄱ'),
(5, '투명 교정', 'clear-aligner', 'Clear Aligner', '투명 교정', '투명 플라스틱 장치로 치아를 이동시키는 교정', '인비절라인 등 투명 교정장치를 순차적으로 착용하여 치아를 서서히 이동시키는 교정 방법입니다. 눈에 잘 띄지 않아 성인에게 인기입니다.', 'tmj-ortho', 'ㅌ'),
(5, '부정교합', 'malocclusion', 'Malocclusion', '부정교합', '위아래 치아가 정상적으로 맞물리지 않는 상태', '1급(치열 불균형), 2급(돌출입), 3급(주걱턱) 등으로 분류되며, 저작 기능, 발음, 심미에 영향을 줍니다.', 'tmj-ortho', 'ㅂ'),
(5, '측두하악관절', 'tmj-joint', 'Temporomandibular Joint', '측두하악관절', '귀 앞쪽에 위치한 턱뼈와 두개골의 관절', '하악골(아래턱뼈)과 측두골(두개골)이 만나는 관절로, 인체에서 가장 복잡한 관절 중 하나입니다. 입을 벌리고, 닫고, 좌우로 움직이게 합니다.', 'tmj', 'ㅊ'),
(5, '교합지', 'articulating-paper', 'Articulating Paper', '교합지', '치아 접촉 부위를 표시하는 얇은 색 종이', '치아가 맞물리는 위치를 확인하기 위해 사용하는 빨간색 또는 파란색의 매우 얇은 종이입니다. 보철 후 교합 조정에 필수적입니다.', 'tmj-ortho', 'ㄱ'),

-- ─── 6. 소아·예방 (15개) ───
(6, '유치', 'deciduous-tooth', 'Deciduous Tooth', '유치', '어린이의 첫 번째 치아(젖니)', '생후 6개월부터 나기 시작하여 총 20개가 나오는 아이의 첫 번째 치아입니다. 6~12세에 걸쳐 영구치로 교환됩니다.', 'general', 'ㅇ'),
(6, '영구치', 'permanent-tooth', 'Permanent Tooth', '영구치', '유치 이후 나오는 평생 사용하는 치아', '유치가 빠진 후 나오는 성인의 치아로, 총 28~32개(사랑니 포함)입니다. 한 번 상실되면 자연 재생되지 않습니다.', 'general', 'ㅇ'),
(6, '실란트', 'sealant', 'Dental Sealant', '실란트', '충치 예방을 위해 치아 홈을 메우는 코팅', '어금니의 좁고 깊은 홈(소와 열구)에 충치가 생기기 쉬우므로, 플라스틱 코팅제로 홈을 메워 세균과 음식물 침착을 방지합니다. 소아에게 추천됩니다.', 'general', 'ㅅ'),
(6, '불소 도포', 'fluoride-application', 'Fluoride Application', '불소 도포', '치아 표면에 불소를 발라 충치를 예방하는 시술', '고농도 불소 젤이나 바니쉬를 치아 표면에 도포하여 법랑질을 강화하고 충치 발생을 억제하는 예방 시술입니다.', 'general', 'ㅂ'),
(6, '맹출', 'eruption', 'Tooth Eruption', '맹출', '치아가 잇몸을 뚫고 구강 안으로 나오는 과정', '치아가 턱뼈 속에서 잇몸을 뚫고 구강 내로 나타나는 과정입니다. 유치는 생후 6개월경, 영구치는 6세경부터 시작됩니다.', 'general', 'ㅁ'),
(6, '과잉치', 'supernumerary-tooth', 'Supernumerary Tooth', '과잉치', '정상 치아 수보다 더 많이 나는 여분의 치아', '정상 치열에 추가로 발생하는 치아로, 특히 상악 앞니 부위에 많이 나타납니다. 영구치 맹출을 방해하면 발치합니다.', 'general', 'ㄱ'),
(6, '유착치', 'ankylosed-tooth', 'Ankylosed Tooth', '유착치', '뼈에 붙어버려 정상적으로 빠지지 않는 치아', '치아 뿌리가 주위 뼈와 직접 유착되어 치주인대 없이 고정된 상태입니다. 유치가 유착되면 영구치 맹출에 장애가 됩니다.', 'general', 'ㅇ'),

-- ─── 7. 구강외과 (15개) ───
(7, '발치', 'extraction', 'Tooth Extraction', '발치', '치아를 뽑는 시술', '보존이 불가능한 치아를 외과적으로 제거하는 시술입니다. 단순 발치와 매복치 등을 위한 외과적 발치로 나뉩니다.', 'general', 'ㅂ'),
(7, '사랑니', 'wisdom-tooth', 'Wisdom Tooth', '사랑니', '가장 늦게 나오는 세 번째 큰어금니', '제3대구치로, 17~25세에 나옵니다. 공간이 부족하면 매복되거나 비스듬히 나서 염증, 통증을 유발하여 발치가 필요합니다.', 'general', 'ㅅ'),
(7, '매복치', 'impacted-tooth', 'Impacted Tooth', '매복치', '잇몸이나 뼈 속에 묻혀 나오지 못하는 치아', '정상적으로 맹출하지 못하고 잇몸이나 뼈 안에 전부 또는 일부가 묻혀 있는 치아입니다. 사랑니에서 가장 흔합니다.', 'general', 'ㅁ'),
(7, '건성 소켓', 'dry-socket', 'Dry Socket', '건성 소켓', '발치 후 혈병이 빠져나가 뼈가 노출된 상태', '발치 후 정상적으로 형성되어야 할 혈병(피떡)이 녹거나 빠져 뼈가 노출되면서 심한 통증이 발생하는 합병증입니다.', 'general', 'ㄱ'),
(7, '구강암', 'oral-cancer', 'Oral Cancer', '구강암', '구강 내에 발생하는 악성 종양', '혀, 잇몸, 입천장, 입술, 뺨 안쪽 등에 발생하는 암입니다. 장기간 낫지 않는 구내염이나 덩어리가 있으면 검사가 필요합니다.', 'general', 'ㄱ'),
(7, '낭종', 'cyst', 'Dental Cyst', '낭종', '턱뼈나 구강 조직 내에 생기는 액체가 찬 주머니', '턱뼈 안에 액체가 채워진 주머니 형태의 병변입니다. 치근단 낭종, 함치성 낭종 등 여러 종류가 있으며, 수술로 제거합니다.', 'general', 'ㄴ'),
(7, '봉합', 'suture', 'Suture', '봉합', '수술 후 잇몸을 꿰매는 시술', '발치, 임플란트, 잇몸 수술 후 절개된 조직을 실로 꿰매어 상처 치유를 돕는 시술입니다. 흡수성 실과 비흡수성 실이 있습니다.', 'general', 'ㅂ'),

-- ─── 8. 디지털·장비 (20개) ───
(8, 'CBCT', 'cbct', 'Cone Beam Computed Tomography', '씨비시티', '치과용 3차원 CT 영상 장비', '콘빔 방식의 3차원 X-ray 촬영 장비로, 턱뼈, 치아, 신경관의 입체적 구조를 정밀하게 파악할 수 있습니다. 임플란트 계획, 매복치 진단 등에 필수적입니다.', 'implant', 'ㅅ'),
(8, '구강 스캐너', 'oral-scanner', 'Intraoral Scanner', '구강 스캐너', '구강 내부를 디지털 3D로 스캔하는 장비', '인상재(본뜨기) 없이 구강 내부를 직접 스캔하여 정밀한 3D 디지털 모델을 생성하는 장비입니다. 보철, 교정, 임플란트에 활용됩니다.', 'implant', 'ㄱ'),
(8, '파노라마', 'panoramic-xray', 'Panoramic X-ray', '파노라마', '상하악 전체를 한 장에 촬영하는 X-ray', '턱뼈, 치아, 상악동 등을 한 번에 넓게 촬영하는 X-ray입니다. 전반적인 구강 상태 파악과 기본 진단에 사용됩니다.', 'general', 'ㅍ'),
(8, '3D 프린터', '3d-printer', '3D Printer', '쓰리디 프린터', '디지털 설계를 물리적 모델로 출력하는 장비', '치과에서는 임플란트 가이드, 교정 장치, 임시 보철 등을 직접 출력하는 데 사용됩니다. 이음치과에서는 원내 가이드 제작에 활용합니다.', 'implant', 'ㅅ'),
(8, 'CAD/CAM', 'cad-cam', 'Computer-Aided Design/Manufacturing', '캐드캠', '컴퓨터 설계·제작 보철 시스템', '컴퓨터로 보철물을 설계(CAD)하고 밀링 머신으로 정밀 가공(CAM)하는 디지털 보철 제작 시스템입니다.', 'aesthetic', 'ㅋ'),
(8, '플라즈마 소독기', 'plasma-sterilizer', 'Plasma Sterilizer', '플라즈마 소독기', '저온 플라즈마를 이용한 첨단 멸균 장비', '과산화수소 플라즈마를 이용하여 저온에서 의료 기구를 완전히 멸균하는 최첨단 감염 관리 장비입니다.', 'general', 'ㅍ'),
(8, '아쿠아케어', 'aquacare', 'AquaCare', '아쿠아케어', '미세 분말을 이용한 최소 침습 충치 제거 장비', '물과 미세 분말을 분사하여 충치 부위만 선택적으로 제거하는 장비로, 드릴 사용을 줄이고 건강한 치아 조직을 보존합니다.', 'resin', 'ㅇ'),
(8, '니트람', 'nitram', 'NiTi Rotary System', '니트람', '니켈티타늄 회전 근관 치료 시스템', 'NiTi(니켈티타늄) 합금 파일을 사용하여 효율적이고 안전하게 근관을 성형하는 자동화 시스템입니다.', 'general', 'ㄴ'),
(8, '교합기', 'articulator', 'Articulator', '교합기', '턱 움직임을 재현하는 기계식 장치', '환자의 교합과 턱 운동을 기계적으로 재현하여 보철물을 제작하는 기공용 장비입니다.', 'aesthetic', 'ㄱ'),
(8, '바이트 등록', 'bite-registration', 'Bite Registration', '바이트 등록', '위아래 치아의 맞물림 관계를 기록하는 과정', '실리콘이나 왁스 등의 재료로 상하 치아의 교합 관계를 정확하게 기록하여 보철물 제작에 반영합니다.', 'aesthetic', 'ㅂ'),
(8, '디지털 인상', 'digital-impression', 'Digital Impression', '디지털 인상', '구강스캐너로 치아 형태를 3D 데이터로 기록하는 방법', '기존의 인상재(본뜨기) 대신 구강스캐너를 이용하여 치아와 잇몸의 형태를 디지털 3D 데이터로 정밀하게 기록합니다.', 'implant', 'ㄷ'),

-- ─── 9. 재료·기술 (15개) ───
(9, '티타늄', 'titanium', 'Titanium', '티타늄', '임플란트의 주된 재료인 생체 친화성 금속', '가볍고 강하며 생체 적합성이 뛰어난 금속으로, 인체에 거부 반응을 거의 일으키지 않아 임플란트 픽스처의 주 재료로 사용됩니다.', 'implant', 'ㅌ'),
(9, '세라믹', 'ceramic', 'Dental Ceramic', '세라믹', '치과에서 사용하는 도자기 계열 소재의 총칭', '도자기 원리를 응용한 치과 재료로, 자연치아와 유사한 색감과 투명도를 구현합니다. 크라운, 라미네이트, 인레이 등에 사용됩니다.', 'aesthetic', 'ㅅ'),
(9, '본딩', 'bonding', 'Dental Bonding', '본딩', '레진 등의 수복 재료를 치아에 접착하는 기술', '산 부식(에칭) 후 접착제(본딩 에이전트)를 도포하여 레진 복합재를 치아에 화학적으로 결합시키는 접착 기술입니다.', 'resin', 'ㅂ'),
(9, '에칭', 'etching', 'Acid Etching', '에칭', '치아 표면을 산처리하여 접착력을 높이는 과정', '인산 젤로 법랑질 표면을 미세하게 거칠게 만들어 본딩제와 레진이 치아에 잘 붙도록 하는 전처리 과정입니다.', 'resin', 'ㅇ'),
(9, '인상', 'dental-impression', 'Dental Impression', '인상', '치아와 잇몸의 형태를 본뜨는 과정', '알지네이트, 실리콘 등의 인상재를 트레이에 담아 구강에 넣어 치아와 잇몸의 형태를 정확하게 복제하는 과정입니다.', 'aesthetic', 'ㅇ'),
(9, '왁스업', 'wax-up', 'Diagnostic Wax-Up', '왁스업', '보철물의 최종 형태를 왁스로 미리 만들어보는 과정', '보철 치료 전에 모형 위에 왁스로 최종 보철물의 형태를 미리 만들어 환자와 상의하고 치료 계획을 확인합니다.', 'aesthetic', 'ㅇ'),
(9, '시멘트', 'dental-cement', 'Dental Cement', '시멘트', '크라운 등의 보철물을 치아에 부착하는 접착제', '크라운, 브릿지, 인레이 등의 보철물을 치아에 고정하는 치과용 접착 재료입니다. 레진 시멘트, GIC 시멘트 등이 있습니다.', 'aesthetic', 'ㅅ'),
(9, '러버댐', 'rubber-dam', 'Rubber Dam', '러버댐', '치료 중 치아를 격리하는 고무 시트', '근관치료나 레진 수복 시 해당 치아를 구강 환경으로부터 격리하여 타액 오염을 방지하고 정밀한 치료를 가능하게 하는 방습 장치입니다.', 'general', 'ㄹ'),

-- ─── 10. 일반·해부 (20개) ───
(10, '절치', 'incisor', 'Incisor', '절치', '앞니. 음식을 자르는 역할을 하는 치아', '위아래 각 4개씩 총 8개의 앞니로, 음식을 베어 자르는 역할을 합니다. 심미적으로도 가장 중요한 치아입니다.', 'general', 'ㅈ'),
(10, '견치', 'canine', 'Canine', '견치', '송곳니. 음식을 찢는 역할을 하는 뾰족한 치아', '앞니와 어금니 사이에 위치한 뾰족한 치아로, 음식을 찢는 역할을 합니다. 치아 중 뿌리가 가장 깁니다.', 'general', 'ㄱ'),
(10, '소구치', 'premolar', 'Premolar', '소구치', '작은 어금니. 음식을 부수고 가는 역할', '견치와 대구치 사이에 있는 치아로, 음식물을 부수고 잘게 가는 역할을 합니다. 상하 각 4개씩 총 8개입니다.', 'general', 'ㅅ'),
(10, '대구치', 'molar', 'Molar', '대구치', '큰 어금니. 음식을 갈아서 부수는 주된 역할', '구강 뒤쪽에 위치한 가장 큰 치아로, 음식물을 잘게 갈아서 소화를 돕습니다. 사랑니를 포함하여 상하 각 6개씩입니다.', 'general', 'ㄷ'),
(10, '치관', 'tooth-crown', 'Tooth Crown', '치관', '잇몸 위로 보이는 치아 부분', '치아에서 법랑질로 덮여 있고 구강 내에 노출되어 보이는 부분입니다. 저작, 발음, 심미를 담당합니다.', 'general', 'ㅊ'),
(10, '치근', 'tooth-root', 'Tooth Root', '치근', '잇몸 아래 뼈 속에 묻혀 있는 치아 뿌리', '치조골 속에 묻혀 치아를 지지하는 부분으로, 시멘트질로 덮여 있고 치주인대를 통해 뼈와 연결됩니다.', 'general', 'ㅊ'),
(10, '치주인대', 'periodontal-ligament', 'Periodontal Ligament', '치주인대', '치아 뿌리와 뼈를 연결하는 섬유 조직', '치근과 치조골 사이의 좁은 공간에 있는 결합조직으로, 치아에 가해지는 힘을 완충하고 뼈에 전달합니다.', 'general', 'ㅊ'),
(10, '치은', 'gingiva', 'Gingiva', '치은', '잇몸. 치아 주변을 둘러싸는 점막 조직', '치아와 치조골을 덮고 보호하는 구강 점막 조직입니다. 건강한 잇몸은 분홍색이며, 단단하고 탄력이 있습니다.', 'general', 'ㅊ'),
(10, '구강 건조증', 'dry-mouth', 'Xerostomia', '구강 건조증', '침 분비가 줄어 입이 마르는 증상', '타액 분비가 감소하여 구강이 건조해지는 상태입니다. 약물 부작용, 당뇨, 방사선 치료 등이 원인이며, 충치 위험이 증가합니다.', 'general', 'ㄱ'),
(10, '구내염', 'stomatitis', 'Stomatitis', '구내염', '구강 점막에 발생하는 염증', '입안 점막에 궤양이나 발적이 생기는 염증성 질환입니다. 아프타성 구내염(입병)이 가장 흔합니다.', 'general', 'ㄱ'),
(10, '타액', 'saliva', 'Saliva', '타액', '침. 구강 건강에 필수적인 체액', '타액선에서 분비되는 체액으로, 구강을 씻어내고, 소화를 돕고, 세균 증식을 억제하며, 치아를 재광화하는 중요한 역할을 합니다.', 'general', 'ㅌ'),
(10, '치아 번호', 'tooth-numbering', 'Tooth Numbering System', '치아 번호', '치아를 체계적으로 구분하기 위한 번호 체계', 'FDI 표기법에서는 성인 치아를 11~48번으로 표기합니다. 첫 자리는 사분면(1~4), 둘째 자리는 치아 순서(1~8)를 나타냅니다.', 'general', 'ㅊ'),
(10, '치식', 'dental-formula', 'Dental Formula', '치식', '치아의 종류와 수를 나타내는 공식', '성인은 2-1-2-3(절치-견치-소구치-대구치)으로 한 사분면에 8개, 총 32개의 치아를 가집니다.', 'general', 'ㅊ'),
(10, '교두', 'cusp', 'Cusp', '교두', '어금니 윗면의 뾰족한 돌기', '소구치와 대구치 교합면의 뾰족하게 올라온 부분으로, 음식을 갈고 부수는 역할을 합니다.', 'general', 'ㄱ'),
(10, '치경부', 'cervical-area', 'Cervical Area', '치경부', '치아와 잇몸이 만나는 목 부위', '치관과 치근이 만나는 부위로, 잇몸이 내려가면 이 부분이 노출되어 시린 증상이 나타날 수 있습니다.', 'general', 'ㅊ'),
(10, '백악질', 'cementum', 'Cementum', '백악질', '치아 뿌리를 감싸는 얇은 석회화 조직', '치근 표면을 덮고 있는 얇은 층으로, 치주인대의 섬유가 이곳에 부착됩니다.', 'general', 'ㅂ'),
(10, '마취', 'anesthesia', 'Dental Anesthesia', '마취', '치료 시 통증을 없애기 위한 약물 처치', '치과 치료 시 통증을 제거하기 위해 사용하는 방법으로, 국소마취(침윤마취, 전달마취)가 가장 많이 사용됩니다.', 'general', 'ㅁ'),
(10, '치아 외상', 'dental-trauma', 'Dental Trauma', '치아 외상', '외부 충격으로 인한 치아 손상', '낙상, 교통사고, 스포츠 등으로 치아가 깨지거나, 빠지거나, 흔들리는 손상입니다. 빠른 응급 처치가 중요합니다.', 'general', 'ㅊ'),
(10, '이소맹출', 'ectopic-eruption', 'Ectopic Eruption', '이소맹출', '치아가 정상 위치가 아닌 곳으로 나오는 것', '치아가 비정상적인 방향이나 위치로 맹출하는 것으로, 치열 문제를 일으킬 수 있습니다.', 'general', 'ㅇ'),
(10, '지각 과민', 'hypersensitivity', 'Dentin Hypersensitivity', '지각 과민', '시린이. 찬 것이나 달콤한 것에 날카로운 통증을 느끼는 증상', '상아질이 노출되어 외부 자극이 상아세관을 통해 신경에 전달되면서 날카로운 통증이 발생하는 상태입니다. 시린이 전용 치약이나 치과 처치로 관리합니다.', 'general', 'ㅈ');

