-- ─── 1. 임플란트 보강 (10개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(1, 'All-on-4', 'all-on-4', 'All-on-4', '올온포', '4개의 임플란트로 전체 치아를 복원하는 기술', '한 악궁에 4개의 임플란트만 심어 전체 치아를 지지하는 고정식 보철 방법입니다. 뒤쪽 2개를 경사 식립하여 긴 보철물을 지탱하며, 수술 당일 임시 치아 장착이 가능합니다.', 'implant', 'ㅇ'),
(1, '발치 후 즉시 식립', 'immediate-placement', 'Immediate Placement', '발치 후 즉시 식립', '치아를 뽑은 자리에 바로 임플란트를 심는 시술', '발치와 동시에 임플란트를 식립하여 치료 기간을 단축합니다. 잔존 뼈의 양과 감염 여부에 따라 가능 여부가 결정됩니다.', 'implant', 'ㅂ'),
(1, '임플란트 보증', 'implant-warranty', 'Implant Warranty', '임플란트 보증', '임플란트 시술 후 제공되는 품질 보증 제도', '임플란트 제조사와 시술 치과에서 제공하는 보증으로, 픽스처 파절이나 조기 실패 시 재시술을 보장합니다. 이음치과에서는 정기 검진 조건 하에 보증을 제공합니다.', 'implant', 'ㅇ'),
(1, '임플란트 식립 각도', 'implant-angulation', 'Implant Angulation', '임플란트 식립 각도', '임플란트를 뼈에 심는 각도와 방향', '보철물의 형태와 교합력 분산을 고려하여 최적의 각도로 임플란트를 식립합니다. 디지털 가이드를 사용하면 계획된 각도로 정확하게 식립할 수 있습니다.', 'implant', 'ㅇ'),
(1, '치조골 보존술', 'ridge-preservation', 'Ridge Preservation', '치조골 보존술', '발치 후 뼈가 흡수되는 것을 막는 시술', '치아를 뽑은 후 빈 공간에 골이식재를 채워 넣어 뼈가 자연 흡수되는 것을 최소화하는 시술입니다. 향후 임플란트 식립을 위한 뼈를 보존합니다.', 'implant', 'ㅊ'),
(1, '서브머지드 임플란트', 'submerged-implant', 'Submerged Implant', '서브머지드 임플란트', '잇몸 아래에 완전히 묻어 치유하는 임플란트 방식', '픽스처 식립 후 잇몸으로 완전히 덮어 뼈와 결합될 때까지 기다린 뒤, 2차 수술로 잇몸을 열어 어버트먼트를 연결하는 2단계 방식입니다.', 'implant', 'ㅅ'),
(1, '논서브머지드 임플란트', 'non-submerged-implant', 'Non-submerged Implant', '논서브머지드 임플란트', '잇몸 밖으로 노출시켜 치유하는 1단계 임플란트 방식', '픽스처 상부가 잇몸 밖으로 노출된 상태로 골유착을 기다리는 방식으로, 2차 수술이 필요 없어 환자 부담이 적습니다.', 'implant', 'ㄴ'),
(1, '치유 기간', 'healing-period', 'Healing Period', '치유 기간', '임플란트가 뼈와 결합되는 데 걸리는 시간', '임플란트 식립 후 골유착이 완료될 때까지의 기간으로, 하악은 2~3개월, 상악은 4~6개월 정도 소요됩니다. 이 기간 동안 과도한 힘을 가하지 않아야 합니다.', 'implant', 'ㅊ'),
(1, '오버덴처', 'overdenture', 'Implant Overdenture', '오버덴처', '임플란트 위에 장착하는 탈착식 틀니', '2~4개의 임플란트에 클립이나 바 형태의 유지장치를 연결하고, 그 위에 틀니를 올리는 방식입니다. 일반 틀니보다 안정적이며 경제적입니다.', 'implant', 'ㅇ'),
(1, '상악동 천공', 'sinus-perforation', 'Sinus Membrane Perforation', '상악동 천공', '상악동 거상술 중 점막이 찢어지는 합병증', '상악동 거상술 시 얇은 상악동 점막이 찢어지는 합병증입니다. 소규모 천공은 수복 가능하며, 경험 많은 술자가 시행하면 위험이 줄어듭니다.', 'implant', 'ㅅ');

-- ─── 2. 보철·심미 보강 (15개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(2, '임시치아', 'provisional-tooth', 'Provisional Restoration', '임시치아', '최종 보철 완성 전까지 사용하는 임시 보철물', '보철 치료 기간 동안 심미성과 기능을 유지하기 위해 장착하는 임시 보철물입니다. 레진이나 PMMA로 제작되며, 환자가 미리 결과를 확인할 수 있습니다.', 'aesthetic', 'ㅇ'),
(2, 'e.max', 'emax', 'IPS e.max', '이맥스', '리튬 디실리케이트 계열의 고강도 세라믹 소재', 'IPS e.max는 강도와 심미성을 모두 갖춘 올세라믹 소재입니다. 자연치아와 매우 유사한 투명도와 색감을 구현하여 앞니 크라운과 라미네이트에 이상적입니다.', 'aesthetic', 'ㅇ'),
(2, '포스트 코어', 'post-core', 'Post and Core', '포스트 코어', '신경치료한 치아에 삽입하는 기둥과 심', '근관치료 후 약해진 치아 내부에 금속이나 섬유 기둥을 세우고 심을 만들어 크라운이 안정적으로 올라갈 수 있는 토대를 만듭니다.', 'aesthetic', 'ㅍ'),
(2, '금관', 'gold-crown', 'Gold Crown', '금관', '금으로 제작한 크라운', '금합금으로 만든 크라운으로, 인체 친화적이고 자연치아와 유사한 마모도를 가집니다. 심미적이지 않지만 어금니에서 내구성이 뛰어납니다.', 'aesthetic', 'ㄱ'),
(2, '잔존 치질', 'remaining-tooth-structure', 'Remaining Tooth Structure', '잔존 치질', '충치 제거 후 남아있는 건강한 치아 조직', '충치나 파절 등으로 손상된 부위를 제거한 후 남아있는 건강한 치아 조직입니다. 남아있는 치질의 양에 따라 수복 방법이 결정됩니다.', 'aesthetic', 'ㅈ'),
(2, '핫셋', 'hot-set', 'Hot Set', '핫셋', '보철물 제작 시 도재를 소성하는 과정', '기공소에서 세라믹 보철물을 제작할 때 고온에서 도자기를 구워 단단하게 만드는 과정입니다.', 'aesthetic', 'ㅎ'),
(2, '마진', 'margin', 'Crown Margin', '마진', '크라운이 치아와 만나는 경계 부분', '크라운의 가장자리와 삭제된 치아가 만나는 경계선입니다. 이 부분의 적합도가 보철의 수명과 2차 충치 예방에 매우 중요합니다.', 'aesthetic', 'ㅁ'),
(2, '프로비저널', 'provisional', 'Provisional Restoration', '프로비저널', '최종 보철 전 치아를 보호하는 임시 수복물', '보철물 제작 기간 동안 삭제된 치아를 보호하고 심미성과 기능을 유지합니다. 이 기간에 환자가 형태와 색을 미리 경험할 수 있습니다.', 'aesthetic', 'ㅍ'),
(2, '치아 삭제', 'tooth-preparation', 'Tooth Preparation', '치아 삭제', '크라운을 씌우기 위해 치아를 다듬는 과정', '보철물이 올라갈 공간을 확보하기 위해 치아를 균일하게 깎는 과정입니다. 삭제량은 보철물 재료에 따라 다릅니다.', 'aesthetic', 'ㅊ'),
(2, '대합치', 'opposing-tooth', 'Opposing Tooth', '대합치', '위아래로 맞물리는 반대편 치아', '교합 시 서로 마주 닿는 반대쪽 악궁의 치아입니다. 보철 치료 시 대합치와의 교합 관계를 반드시 고려해야 합니다.', 'aesthetic', 'ㄷ'),
(2, '치아 재식', 'replantation', 'Tooth Replantation', '치아 재식', '빠진 치아를 다시 심는 시술', '외상으로 완전히 빠진 치아를 원래 자리에 다시 심는 응급 시술입니다. 빠진 후 30분 이내에 우유나 식염수에 담가 가져오면 성공률이 높습니다.', 'general', 'ㅊ'),
(2, '디지털 스마일 디자인', 'digital-smile-design', 'Digital Smile Design', '디지털 스마일 디자인', '컴퓨터로 미리 보는 미소 시뮬레이션', '환자의 얼굴 사진과 구강 스캔 데이터를 바탕으로 보철 치료 후의 미소를 디지털로 미리 디자인하고 시뮬레이션합니다.', 'aesthetic', 'ㄷ'),
(2, '교합 조정', 'occlusal-adjustment', 'Occlusal Adjustment', '교합 조정', '치아의 맞물림을 미세하게 다듬는 시술', '보철물 장착 후 또는 자연치의 교합이 불균형할 때 교합지로 접촉점을 확인하고 미세하게 다듬어 균형 잡힌 교합을 만듭니다.', 'aesthetic', 'ㄱ'),
(2, '심미 라인', 'smile-line', 'Smile Line', '심미 라인', '미소 지을 때 윗입술이 그리는 곡선', '웃을 때 보이는 치아와 잇몸의 경계선입니다. 이상적인 심미 라인은 위쪽 앞니의 절단면이 아래 입술의 곡선과 일치합니다.', 'aesthetic', 'ㅅ'),
(2, '치관 길이 연장술', 'crown-lengthening', 'Crown Lengthening', '치관 길이 연장술', '잇몸이나 뼈를 다듬어 보이는 치아 길이를 늘리는 수술', '잇몸이 많이 보이는 거미 스마일이나 크라운 장착을 위한 치아 길이가 부족할 때, 잇몸과 뼈를 정리하여 치관 길이를 확보합니다.', 'aesthetic', 'ㅊ');

-- ─── 3. 보존·근관 보강 (10개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(3, '2차 충치', 'secondary-caries', 'Secondary Caries', '이차 충치', '이전 치료한 충전물 주변에 다시 생기는 충치', '기존 레진이나 아말감 충전물의 경계면이 벌어지거나 미세 누출이 생겨 그 틈으로 세균이 침투하여 발생하는 충치입니다.', 'resin', 'ㅇ'),
(3, '직접 수복', 'direct-restoration', 'Direct Restoration', '직접 수복', '구강 내에서 직접 재료를 채워 수복하는 방법', '레진 등의 재료를 치아에 직접 적용하여 충전하는 방법입니다. 기공 과정이 필요 없어 당일 치료가 가능합니다.', 'resin', 'ㅈ'),
(3, '간접 수복', 'indirect-restoration', 'Indirect Restoration', '간접 수복', '기공소에서 제작한 수복물을 접착하는 방법', '구강을 본뜬 후 기공소에서 인레이, 온레이, 크라운 등을 제작하여 접착하는 수복 방법입니다. 정밀도가 높습니다.', 'aesthetic', 'ㄱ'),
(3, '광중합', 'light-curing', 'Light Curing', '광중합', 'LED 빛으로 레진을 굳히는 과정', '레진 복합재에 가시광선(LED)을 조사하여 화학적으로 경화시키는 과정입니다. 레이어별로 광조사하여 수축을 최소화합니다.', 'resin', 'ㄱ'),
(3, '치수 괴사', 'pulp-necrosis', 'Pulp Necrosis', '치수 괴사', '치아 내부 신경이 죽은 상태', '충치, 외상, 또는 혈류 차단으로 치수 조직이 사멸한 상태입니다. 통증이 없어질 수 있지만 감염 위험이 높아 신경치료가 필요합니다.', 'general', 'ㅊ'),
(3, '치근단 병변', 'periapical-lesion', 'Periapical Lesion', '치근단 병변', '치아 뿌리 끝에 생기는 염증성 병변', '신경이 죽은 치아의 뿌리 끝에 세균 감염으로 인해 고름이 차거나 낭종이 형성되는 병변입니다. X-ray에서 검은 그림자로 나타납니다.', 'general', 'ㅊ'),
(3, '치아 파절', 'tooth-fracture', 'Tooth Fracture', '치아 파절', '치아가 깨지거나 금이 가는 상태', '외상이나 과도한 교합력으로 치아에 금이 가거나 깨지는 상태입니다. 법랑질만 깨진 경우부터 뿌리까지 파절된 경우까지 다양합니다.', 'general', 'ㅊ'),
(3, '미세 누출', 'microleakage', 'Microleakage', '미세 누출', '충전물과 치아 사이의 미세한 틈으로 세균이 침투하는 현상', '수복물과 치아 경계면의 미세한 간극으로 타액과 세균이 들어가는 현상입니다. 2차 충치의 주원인이며, 정밀한 접착이 중요합니다.', 'resin', 'ㅁ'),
(3, '수산화 칼슘', 'calcium-hydroxide', 'Calcium Hydroxide', '수산화 칼슘', '치수 보호에 사용되는 기본 약제', '강한 알칼리성으로 살균 작용이 있으며, 치수 복조술이나 근관 내 소독에 사용됩니다. 새로운 상아질 형성을 촉진합니다.', 'general', 'ㅅ'),
(3, '치수 생활력 검사', 'pulp-vitality-test', 'Pulp Vitality Test', '치수 생활력 검사', '치아 신경이 살아있는지 확인하는 검사', '차가운 자극(냉검사), 전기 자극(전기 생활력 검사) 등을 이용하여 치수의 생사 여부를 판별하는 진단 방법입니다.', 'general', 'ㅊ');

-- ─── 4. 치주·잇몸 보강 (8개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(4, '치주 프로빙', 'periodontal-probing', 'Periodontal Probing', '치주 프로빙', '치주낭 깊이를 측정하는 검사', '치주 탐침(프로브)을 잇몸과 치아 사이에 넣어 치주낭의 깊이를 mm 단위로 측정합니다. 4mm 이상이면 치주질환을 의심합니다.', 'general', 'ㅊ'),
(4, '치태 조절', 'plaque-control', 'Plaque Control', '치태 조절', '올바른 칫솔질과 구강 관리로 치태를 관리하는 것', '올바른 칫솔질, 치실, 치간 칫솔 사용으로 치태 형성을 억제하는 자가 관리법입니다. 치주 치료의 가장 기본이 됩니다.', 'general', 'ㅊ'),
(4, '잇몸 퇴축', 'gum-recession', 'Gum Recession', '잇몸 퇴축', '잇몸이 아래로 내려가 치아 뿌리가 노출되는 상태', '잇몸 조직이 점차 줄어들어 치근이 드러나는 상태입니다. 과도한 칫솔질, 치주염, 교합 외상 등이 원인이며, 시린 증상이 나타납니다.', 'general', 'ㅇ'),
(4, '에어플로우', 'airflow', 'Airflow', '에어플로우', '미세 분말을 분사하여 착색과 바이오필름을 제거하는 장비', '글리신 분말과 공기, 물을 혼합 분사하여 치아 표면의 착색, 바이오필름, 연성 침착물을 효과적으로 제거하는 예방 치료 장비입니다.', 'general', 'ㅇ'),
(4, '유지 관리', 'maintenance-therapy', 'Periodontal Maintenance', '유지 관리', '치주 치료 후 정기적으로 관리하는 프로그램', '활동기 치주 치료 완료 후 3~6개월 간격으로 정기 검진과 스케일링을 받아 재발을 방지하는 장기 관리 프로그램입니다.', 'general', 'ㅇ'),
(4, '치은 비대', 'gingival-hyperplasia', 'Gingival Hyperplasia', '치은 비대', '잇몸이 비정상적으로 부풀어 오르는 상태', '약물(항경련제, 면역억제제 등), 치태 축적, 호르몬 변화 등으로 잇몸이 비정상적으로 커지는 상태입니다.', 'general', 'ㅊ'),
(4, '출혈 지수', 'bleeding-index', 'Bleeding on Probing', '출혈 지수', '치주 프로빙 시 잇몸 출혈 여부를 기록하는 지표', '치주낭 측정 시 출혈이 있으면 활동성 염증이 있다는 의미입니다. 치주 치료 효과를 평가하는 중요한 지표입니다.', 'general', 'ㅊ'),
(4, '치주 재생술', 'periodontal-regeneration', 'Periodontal Regeneration', '치주 재생술', '소실된 치주 조직을 재생시키는 수술', '치주염으로 파괴된 치조골과 치주인대를 골이식재, 차폐막, 성장인자 등을 이용하여 재생시키는 첨단 치주 수술입니다.', 'general', 'ㅊ');

-- ─── 5. 턱관절·교정 보강 (10개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(5, '디스크 변위', 'disc-displacement', 'Disc Displacement', '디스크 변위', '턱관절 디스크가 정상 위치에서 벗어난 상태', '관절원판(디스크)이 정상 위치에서 앞쪽으로 이탈한 상태입니다. 입을 벌릴 때 딸깍 소리가 나거나 벌리기 어려운 증상이 나타납니다.', 'tmj', 'ㄷ'),
(5, '턱관절 클릭', 'tmj-clicking', 'TMJ Clicking', '턱관절 클릭', '입을 벌리거나 닫을 때 턱에서 나는 딸깍 소리', '디스크 변위로 인해 입을 벌릴 때 디스크가 정상 위치로 돌아가면서 나는 소리입니다. 통증이 없으면 경과 관찰합니다.', 'tmj', 'ㅌ'),
(5, '턱관절 잠김', 'tmj-locking', 'TMJ Locking', '턱관절 잠김', '턱이 벌어지지 않거나 다물어지지 않는 상태', '디스크가 걸려서 입이 안 벌어지는 폐구장애, 또는 입이 안 다물어지는 개구장애로 나뉩니다.', 'tmj', 'ㅌ'),
(5, '교합 간섭', 'occlusal-interference', 'Occlusal Interference', '교합 간섭', '정상적인 턱 운동을 방해하는 비정상적 치아 접촉', '턱을 옆으로 움직이거나 다물 때 특정 치아가 먼저 닿아 턱 운동을 방해하는 것으로, 턱관절 장애의 원인이 될 수 있습니다.', 'tmj', 'ㄱ'),
(5, '보톡스 치료', 'botox-tmj', 'Botox for TMJ', '보톡스 치료', '교근에 보톡스를 주사하여 턱관절 증상을 완화하는 치료', '이갈이나 이 악물기로 비대해진 교근에 보톡스를 주사하여 근육을 이완시키고 턱관절 부담을 줄이는 보조적 치료법입니다.', 'tmj', 'ㅂ'),
(5, '브래킷', 'bracket', 'Orthodontic Bracket', '브래킷', '교정 치료 시 치아에 붙이는 작은 장치', '치아 표면에 접착하여 교정 와이어를 고정하는 작은 금속 또는 세라믹 장치입니다. 교정력을 치아에 전달하는 역할을 합니다.', 'tmj-ortho', 'ㅂ'),
(5, '교정 와이어', 'orthodontic-wire', 'Orthodontic Wire', '교정 와이어', '브래킷에 걸어 치아를 이동시키는 금속 선', '니켈티타늄이나 스테인리스 합금으로 만든 금속 선으로, 브래킷에 걸어 탄성력으로 치아를 원하는 위치로 이동시킵니다.', 'tmj-ortho', 'ㄱ'),
(5, '유지 장치', 'retainer', 'Orthodontic Retainer', '유지 장치', '교정 치료 후 치아 위치를 유지하는 장치', '교정이 끝난 후 치아가 다시 원래 위치로 돌아가는 것(재발)을 막기 위해 착용하는 장치입니다. 고정식과 가철식이 있습니다.', 'tmj-ortho', 'ㅇ'),
(5, '안면 비대칭', 'facial-asymmetry', 'Facial Asymmetry', '안면 비대칭', '얼굴의 좌우가 불균형한 상태', '골격, 근육, 치아 배열의 불균형으로 얼굴 좌우가 대칭적이지 않은 상태입니다. 심한 경우 교정이나 수술로 개선할 수 있습니다.', 'tmj-ortho', 'ㅇ'),
(5, '물리치료', 'physical-therapy', 'Physical Therapy for TMJ', '물리치료', '턱관절 증상 완화를 위한 비수술적 치료', '온찜질, 초음파 치료, 턱 운동법, 마사지 등을 통해 턱관절 통증과 근육 긴장을 완화하는 보존적 치료 방법입니다.', 'tmj', 'ㅁ');

-- ─── 6. 소아·예방 보강 (8개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(6, '소대 절제술', 'frenectomy', 'Frenectomy', '소대 절제술', '입술이나 혀의 소대를 절제하는 수술', '입술 소대나 설소대가 너무 짧거나 두꺼워 치아 사이 벌어짐이나 발음 장애를 일으킬 때 절제하는 간단한 수술입니다.', 'general', 'ㅅ'),
(6, '영구치 결손', 'congenitally-missing', 'Congenitally Missing Tooth', '영구치 결손', '선천적으로 영구치가 없는 상태', '유치 아래에 영구치 싹이 없어 영구치가 나오지 않는 선천적 결손입니다. 유치를 오래 유지하거나 교정·임플란트로 대체합니다.', 'general', 'ㅇ'),
(6, '바이트 윙', 'bitewing', 'Bitewing X-ray', '바이트 윙', '어금니 충치를 확인하는 X-ray 촬영법', '필름을 물고 촬영하여 어금니 사이 충치를 발견하는 데 특화된 구강 내 X-ray 촬영법입니다. 소아 검진에서 자주 사용됩니다.', 'general', 'ㅂ'),
(6, '치아 나이', 'dental-age', 'Dental Age', '치아 나이', '치아 발육 상태로 평가하는 생물학적 나이', '치아의 맹출 순서와 발육 단계를 기준으로 판별하는 생물학적 나이입니다. 교정 치료 시기 결정에 참고합니다.', 'general', 'ㅊ'),
(6, '공간 유지 장치', 'space-maintainer', 'Space Maintainer', '공간 유지 장치', '유치가 일찍 빠진 자리에 공간을 유지하는 장치', '유치가 일찍 빠지면 영구치가 날 공간이 좁아질 수 있어, 금속 장치로 공간을 유지하여 영구치가 정상적으로 나올 수 있게 합니다.', 'general', 'ㄱ'),
(6, '치면 착색 검사', 'disclosing-test', 'Disclosing Test', '치면 착색 검사', '치태가 어디에 있는지 색으로 보여주는 검사', '착색 용액이나 정제를 사용하여 치아에 붙은 치태를 빨갛게 또는 파랗게 물들여 칫솔질이 안 되는 부위를 눈으로 확인합니다.', 'general', 'ㅊ'),
(6, '수복물 탈락', 'restoration-dislodgement', 'Restoration Dislodgement', '수복물 탈락', '충전물이나 크라운이 빠지는 상태', '레진, 인레이, 크라운 등이 접착력 약화, 2차 충치, 교합력 등으로 빠지는 것입니다. 빠른 시일 내 재접착하거나 재제작해야 합니다.', 'general', 'ㅅ'),
(6, '구호흡', 'mouth-breathing', 'Mouth Breathing', '구호흡', '코 대신 입으로 숨 쉬는 습관', '비염, 아데노이드 비대 등으로 코 대신 입으로 호흡하는 습관입니다. 장기간 지속 시 안면 발육 이상, 부정교합, 구강 건조증을 유발합니다.', 'general', 'ㄱ');

-- ─── 7. 구강외과 보강 (8개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(7, '절개 배농', 'incision-drainage', 'Incision and Drainage', '절개 배농', '고름이 찬 부위를 절개하여 배출하는 응급 시술', '잇몸이나 구강 조직에 고름(농양)이 형성되었을 때 절개하여 고름을 빼내고 감염을 해소하는 응급 시술입니다.', 'general', 'ㅈ'),
(7, '이식 수술', 'autotransplantation', 'Tooth Autotransplantation', '이식 수술', '자기 치아를 다른 부위로 옮겨 심는 수술', '불필요한 사랑니 등을 빠진 다른 치아 자리로 이식하는 수술입니다. 성공하면 임플란트 없이 자연 치아로 기능합니다.', 'general', 'ㅇ'),
(7, '구강 상악동 누공', 'oroantral-fistula', 'Oroantral Fistula', '구강 상악동 누공', '윗어금니 발치 후 입과 상악동이 연결된 상태', '상악 어금니 발치 후 구강과 상악동 사이에 구멍이 생기는 합병증입니다. 음식이 코로 나오거나 축농증이 생길 수 있어 폐쇄 수술이 필요합니다.', 'general', 'ㄱ'),
(7, '골절', 'jaw-fracture', 'Jaw Fracture', '골절', '턱뼈가 부러지는 외상', '교통사고, 낙상, 스포츠 등으로 상악이나 하악이 골절되는 외상입니다. 교합 이상, 부종, 통증이 나타나며, 정복 수술이 필요할 수 있습니다.', 'general', 'ㄱ'),
(7, '하치조 신경', 'inferior-alveolar-nerve', 'Inferior Alveolar Nerve', '하치조 신경', '하악에서 감각을 담당하는 신경', '아래턱뼈 속을 지나는 감각 신경으로, 아래 치아와 아랫입술, 턱의 감각을 담당합니다. 사랑니 발치나 임플란트 시 손상에 주의해야 합니다.', 'general', 'ㅎ'),
(7, '이신경', 'lingual-nerve', 'Lingual Nerve', '이신경', '혀의 감각을 담당하는 신경', '혀의 전방 2/3 감각과 미각을 담당하는 신경입니다. 하악 사랑니 발치 시 드물게 손상될 수 있으며, 혀가 저리거나 맛을 못 느낄 수 있습니다.', 'general', 'ㅇ'),
(7, '국소 마취', 'local-anesthesia', 'Local Anesthesia', '국소 마취', '시술 부위만 마취하는 방법', '리도카인 등의 마취제를 치료 부위에 주사하여 해당 부분만 감각을 차단하는 가장 흔한 치과 마취 방법입니다.', 'general', 'ㄱ'),
(7, '의식 하 진정', 'conscious-sedation', 'Conscious Sedation', '의식 하 진정', '약물로 불안을 줄이면서 의식은 유지하는 진정법', '치과 공포증이 심하거나 긴 시술 시 정맥 진정(수면 마취)으로 불안과 통증을 줄입니다. 환자는 의사소통이 가능한 상태를 유지합니다.', 'general', 'ㅇ');

-- ─── 8. 디지털·장비 보강 (9개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(8, '근관장 측정기', 'apex-locator', 'Electronic Apex Locator', '근관장 측정기', '치아 뿌리 길이를 전자적으로 측정하는 장비', '근관치료 시 치아 뿌리 끝까지의 길이를 정확하게 측정하는 전자 장비입니다. X-ray 촬영 횟수를 줄이고 정확도를 높입니다.', 'general', 'ㄱ'),
(8, '고배율 루페', 'dental-loupes', 'Dental Loupes', '고배율 루페', '치과의사가 착용하는 확대경', '2.5~6배 확대하여 미세한 부위를 정확하게 볼 수 있는 광학 확대 안경입니다. 정밀한 시술 품질을 높여줍니다.', 'general', 'ㄱ'),
(8, '치과 현미경', 'dental-microscope', 'Operating Microscope', '치과 현미경', '최대 25배까지 확대하는 수술용 현미경', '치과 수술용 현미경으로, 미세근관, 파절선 등을 육안으로 확인하기 어려운 구조를 정밀하게 관찰하며 치료합니다.', 'general', 'ㅊ'),
(8, '오토클레이브', 'autoclave', 'Autoclave', '오토클레이브', '고온 고압 증기로 기구를 멸균하는 장비', '121~134°C의 고온 증기를 고압으로 가해 모든 미생물을 사멸시키는 가장 기본적인 멸균 장비입니다. 감염 관리의 핵심입니다.', 'general', 'ㅇ'),
(8, '에어샤워', 'air-shower', 'Air Shower', '에어샤워', '진료실 입장 전 먼지와 이물질을 제거하는 장비', '고압의 공기를 분사하여 옷과 몸에 붙은 먼지, 미세입자를 제거하는 장비입니다. 이음치과에서는 수술실 감염 관리를 위해 운영합니다.', 'general', 'ㅇ'),
(8, '디지털 파노라마', 'digital-panoramic', 'Digital Panoramic X-ray', '디지털 파노라마', '디지털 방식으로 촬영하는 파노라마 X-ray', '필름 대신 디지털 센서로 촬영하여 즉시 고화질 영상을 얻고, 방사선량을 기존의 50~80%까지 줄인 첨단 파노라마 장비입니다.', 'general', 'ㄷ'),
(8, '구강 카메라', 'intraoral-camera', 'Intraoral Camera', '구강 카메라', '구강 내부를 촬영하는 소형 카메라', '작은 카메라 헤드를 입 안에 넣어 치아와 잇몸 상태를 모니터로 확대하여 보여주는 장비입니다. 환자 교육과 기록에 활용됩니다.', 'general', 'ㄱ'),
(8, '석션', 'dental-suction', 'Dental Suction', '석션', '시술 중 물과 타액을 흡입하는 장비', '치료 중 발생하는 물, 타액, 분진 등을 흡입하여 시야를 확보하고 환자의 편안함을 유지하는 필수 장비입니다.', 'general', 'ㅅ'),
(8, '초음파 세척기', 'ultrasonic-cleaner', 'Ultrasonic Cleaner', '초음파 세척기', '초음파 진동으로 기구를 세척하는 장비', '멸균 전 단계로, 초음파 진동을 이용하여 기구 표면과 미세 틈의 오염물을 효과적으로 제거하는 세척 장비입니다.', 'general', 'ㅊ');

-- ─── 9. 재료·기술 보강 (7개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(9, 'PMMA', 'pmma', 'Polymethyl Methacrylate', '피엠엠에이', '임시 보철에 사용되는 아크릴 계열 수지', '내구성이 좋은 아크릴 수지로, 임시 크라운, 의치, 교정장치 등에 널리 사용됩니다. CAD/CAM으로 정밀 가공이 가능합니다.', 'aesthetic', 'ㅍ'),
(9, '차폐막', 'barrier-membrane', 'Barrier Membrane', '차폐막', 'GBR 시 뼈 재생 공간을 확보하는 막', '골이식 시 연조직(잇몸)이 뼈 재생 공간으로 침입하는 것을 막는 생체 적합성 막입니다. 흡수성과 비흡수성이 있습니다.', 'implant', 'ㅊ'),
(9, '이종골', 'xenograft', 'Xenograft', '이종골', '다른 종(주로 소)에서 유래한 골이식재', '소 뼈에서 유기물을 제거하고 무기질 골격만 남긴 이식재입니다. 자가골을 채취하지 않아도 되어 환자 부담이 적습니다.', 'implant', 'ㅇ'),
(9, '합성골', 'alloplast', 'Alloplastic Graft', '합성골', '인공적으로 합성한 골이식 재료', 'β-TCP, 하이드록시아파타이트 등 인공 합성 재료로 만든 골이식재입니다. 감염 위험이 없고 안정적인 공급이 가능합니다.', 'implant', 'ㅎ'),
(9, '실러', 'sealer', 'Root Canal Sealer', '실러', '근관 충전 시 거타퍼차와 함께 사용하는 밀봉재', '근관벽과 거타퍼차 사이의 미세한 간극을 메워 완전한 밀봉을 이루는 접착제 역할의 재료입니다.', 'general', 'ㅅ'),
(9, '교정용 미니 스크류', 'ortho-miniscrew', 'Orthodontic Mini Screw', '교정용 미니 스크류', '교정 치료의 고정원으로 사용하는 작은 나사', '잇몸 뼈에 삽입하는 작은 티타늄 나사로, 치아 이동의 지지점(고정원) 역할을 합니다. 교정 완료 후 쉽게 제거됩니다.', 'tmj-ortho', 'ㄱ'),
(9, '프라이머', 'primer', 'Dental Primer', '프라이머', '치아와 수복 재료의 접착력을 높이는 전처리제', '에칭 후 치아 표면에 도포하여 본딩제가 더 잘 침투하도록 하는 전처리 용액입니다. 레진 수복의 접착 강도를 높입니다.', 'resin', 'ㅍ');

-- ─── 10. 일반·해부 보강 (15개 추가) ───
INSERT INTO dict_terms (category_id, term, slug, english, pronunciation, short_desc, full_desc, related_service, chosung) VALUES
(10, '구강 위생', 'oral-hygiene', 'Oral Hygiene', '구강 위생', '입 안을 청결하게 관리하는 것', '칫솔질, 치실, 가글 등을 통해 구강 내 세균과 음식 잔사를 제거하고 건강한 구강 상태를 유지하는 모든 활동입니다.', 'general', 'ㄱ'),
(10, '치실', 'dental-floss', 'Dental Floss', '치실', '치아 사이를 청소하는 얇은 실', '칫솔이 닿지 않는 치아와 치아 사이의 접촉면을 청소하는 도구입니다. 매일 사용하면 충치와 잇몸병 예방에 효과적입니다.', 'general', 'ㅊ'),
(10, '치간 칫솔', 'interdental-brush', 'Interdental Brush', '치간 칫솔', '치아 사이를 청소하는 작은 솔', '치아 사이 공간이 넓은 경우 치실 대신 사용하는 작은 병 닦는 솔 모양의 구강 위생 도구입니다.', 'general', 'ㅊ'),
(10, '전동 칫솔', 'electric-toothbrush', 'Electric Toothbrush', '전동 칫솔', '전기 모터로 진동하는 칫솔', '진동 또는 회전하는 칫솔머리로 효과적인 칫솔질을 도와주는 도구입니다. 올바른 사용 시 수동 칫솔보다 플라크 제거 효율이 높습니다.', 'general', 'ㅈ'),
(10, '교차 감염', 'cross-infection', 'Cross Infection', '교차 감염', '환자 간 또는 의료진과 환자 간의 감염 전파', '치과 환경에서 혈액, 타액 등을 매개로 감염이 전파되는 것입니다. 멸균, 일회용 용품, 보호 장구 착용으로 예방합니다.', 'general', 'ㄱ'),
(10, '방사선 방호', 'radiation-protection', 'Radiation Protection', '방사선 방호', 'X-ray 촬영 시 방사선을 최소화하는 안전 조치', '납 앞치마(방호복) 착용, 최소 촬영 원칙(ALARA), 디지털 센서 사용 등으로 불필요한 방사선 노출을 줄이는 안전 수칙입니다.', 'general', 'ㅂ'),
(10, '치아 우식증', 'dental-caries', 'Dental Caries', '치아 우식증', '충치의 의학적 명칭', '세균이 생산하는 산에 의해 치아 경조직이 점진적으로 파괴되는 감염성 질환입니다. 충치라는 일상 용어로 불립니다.', 'general', 'ㅊ'),
(10, '구취', 'halitosis', 'Halitosis', '구취', '입에서 나는 불쾌한 냄새', '구강 내 세균, 설태, 치주질환, 건조한 입 등이 원인입니다. 대부분 구강 관리와 치과 치료로 개선됩니다.', 'general', 'ㄱ'),
(10, '설태', 'tongue-coating', 'Tongue Coating', '설태', '혀 표면에 쌓이는 하얀 막', '혀 유두 사이에 세균, 음식 잔사, 탈락 세포가 쌓여 형성되는 막입니다. 구취의 주된 원인이며, 혀 클리너로 관리합니다.', 'general', 'ㅅ'),
(10, '구순 포진', 'cold-sore', 'Cold Sore (Herpes Labialis)', '구순 포진', '입술 주변에 생기는 헤르페스 물집', '단순 포진 바이러스(HSV-1)에 의한 감염으로, 입술이나 입 주변에 작은 물집이 모여 생깁니다. 피로, 스트레스 시 재발합니다.', 'general', 'ㄱ'),
(10, '악관절', 'jaw-joint', 'Jaw Joint', '악관절', '턱뼈와 머리뼈가 만나는 관절의 통칭', '측두하악관절의 일반적인 표현으로, 귀 앞쪽에 위치하며 입을 벌리고 닫는 모든 움직임을 담당합니다.', 'tmj', 'ㅇ'),
(10, '저작', 'mastication', 'Mastication', '저작', '음식을 씹는 행위', '치아와 턱근육을 이용하여 음식을 잘게 부수는 과정입니다. 올바른 저작은 소화를 돕고 치아와 잇몸 건강에 중요합니다.', 'general', 'ㅈ'),
(10, '연하', 'swallowing', 'Swallowing', '연하', '음식을 삼키는 행위', '저작 후 음식물을 인두를 통해 식도로 보내는 과정입니다. 정상적인 연하에는 혀, 구개, 인두 근육의 협조가 필요합니다.', 'general', 'ㅇ'),
(10, '개구', 'mouth-opening', 'Mouth Opening', '개구', '입을 벌리는 동작', '정상 개구량은 약 40~55mm입니다. 턱관절 장애나 근육 긴장으로 개구량이 줄어들면 식사나 치과 치료에 어려움이 생깁니다.', 'tmj', 'ㄱ'),
(10, '농양', 'abscess', 'Dental Abscess', '농양', '세균 감염으로 고름이 모인 상태', '치아 뿌리 끝이나 잇몸에 세균 감염이 심해져 고름이 형성된 상태입니다. 심한 통증, 부종, 발열을 동반하며 신속한 치료가 필요합니다.', 'general', 'ㄴ');
